# Milvus Vector Store Integration\n\nimport milvus\nfrom milvus import Milvus, IndexType, MetricType\n\nclass MilvusVectorStore:\n    def __init__(self, host, port, collection_name):\n        self.client = Milvus(host=host, port=port)\n        self.collection_name = collection_name\n        self._create_collection_if_not_exists()\n\n    def _create_collection_if_not_exists(self):\n        if not self.client.has_collection(self.collection_name)[1]:\n            self.client.create_collection({\n                'name': self.collection_name,\n                'dimension': 128,\n                'index_file_size': 1024,\n                'metric_type': MetricType.L2\n            })\n\n    def insert(self, vectors, ids=None):\n        self.client.insert(collection_name=self.collection_name, records=vectors, ids=ids)\n\n    def search(self, query_vectors, top_k=10):\n        return self.client.search(collection_name=self.collection_name, query_records=query_vectors, top_k=top_k)\n\n    def delete(self, ids):\n        self.client.delete(collection_name=self.collection_name, ids=ids)\n